 */
export interface HandoffDocumentOptions {
  /** Current session ID */
  sessionId: string;
  /** Current Gofer stage */
  currentStage: string;
  /** Current task being worked on */
  currentTask?: string;
  /** Additional context to include */
  additionalContext?: string;
  /** Key decisions made during session */
  keyDecisions?: string[];
  /** Blockers or issues encountered */
  blockers?: string[];
}

